import java.io.File;
import java.io.FileInputStream;
import java.io.FileNotFoundException;

public class Main {
    public static void main(String[] args) {
        // 存在しないファイルを表すFileオブジェクトを作成します。
        File file = new File("non_existent_file.txt");
        // FileInputStreamを作成しようとすると、FileNotFoundExceptionがスローされます。
        try {
            FileInputStream fis = new FileInputStream(file);
        } catch (FileNotFoundException e) {
            // FileNotFoundExceptionがスローされた場合、スタックトレースを出力します。
            e.printStackTrace();
        }
    }
}
```

// チェック例外クラスを継承してカスタム例外クラスを作成します。
public class InvalidUserAgeException extends Exception {
    // コンストラクタでエラーメッセージを設定します。
    public InvalidUserAgeException(int age) {
        super("Invalid age: " + age);
    }
}

public class Main {
    public static void main(String[] args) {
        try {
            // 年齢が不適切な場合に例外をスローします。
            throw new InvalidUserAgeException(-1);
        } catch (InvalidUserAgeException e) {
            // エラーメッセージを表示します。
            System.out.println(e.getMessage());
        }
    }
}
```

import java.io.FileWriter;
