public class Main {
    public static void main(String[] args) {
        try {
            checkNumber(-5);
        } catch (NegativeNumberException e) {
            e.printStackTrace();
        }
    }

    public static void checkNumber(int number) throws NegativeNumberException {
        if (number < 0) {
            throw new NegativeNumberException("Negative number: " + number);
        }
    }
}

