public class Main {
    public static void main(String[] args) {
        try {
            // 値が奇数ならArithmeticExceptionを、偶数ならNullPointerExceptionをスローします
            if (args.length % 2 == 0) {
                throw new NullPointerException("Even length");
            } else {
                throw new ArithmeticException("Odd length");
            }
        } catch (NullPointerException e) {
            System.out.println("Caught NullPointerException: " + e.getMessage());
        } catch (ArithmeticException e) {
            System.out.println("Caught ArithmeticException: " + e.getMessage());
        }
    }
}
```
// 出力結果: Caught NullPointerException: Even length
// もしくは
// 出力結果: Caught ArithmeticException: Odd length

public class Main {
    public static void main(String[] args) {
        try {
            // ファイルを開いて操作するコード
            throw new Exception("A test exception");
        } catch (Exception e) {
            System.out.println("Caught exception: " + e.getMessage());
        } finally {
            // 例外が発生しようとしまいと、ここは必ず実行されます。
            System.out.println("Executing finally block.");
        }
    }
}
```
// 出力結果:
// Caught exception: A test exception
// Executing finally block.

